import{_ as t,c as o,m as e,a as r,t as i,U as n,o as s}from"./chunks/framework.9QHaLlVJ.js";const P=JSON.parse('{"title":"升级配置参数","description":"","frontmatter":{"title":"升级配置参数"},"headers":[],"relativePath":"doc/DevOps/Kubernetes/基础/Deployment/升级策略/升级配置参数.md","filePath":"packages/doc/src/DevOps/Kubernetes/基础/Deployment/升级策略/升级配置参数.md","lastUpdated":1704901837000}'),d={name:"doc/DevOps/Kubernetes/基础/Deployment/升级策略/升级配置参数.md"},l={id:"frontmatter-title",tabindex:"-1"},c=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),p=n('<h2 id="maxsurge-最大浪涌" tabindex="-1">maxSurge 最大浪涌 <a class="header-anchor" href="#maxsurge-最大浪涌" aria-label="Permalink to &quot;maxSurge 最大浪涌&quot;">​</a></h2><p>与spec.replicas相比，可以有多少个Pod存在，默认值是25%。</p><p>比如spec.replicas为 4，那升级过程中就不能超过5个Pod存在，即按1个的步长升级，实际升级过程中会换算成数字，且换算会向上取整。这个值也可以直接设置成数字。</p><p>仅Deployment、DaemonSet支持配置</p><h2 id="maxunavailable-最大无效实例数" tabindex="-1">maxUnavailable 最大无效实例数 <a class="header-anchor" href="#maxunavailable-最大无效实例数" aria-label="Permalink to &quot;maxUnavailable 最大无效实例数&quot;">​</a></h2><p>与spec.replicas相比，可以有多少个Pod失效，也就是删除的比例，默认值是25%。</p><p>比如spec.replicas为4，那升级过程中就至少有3个Pod存在，即删除Pod的步长是1。同样这个值也可以设置成数字。</p><p>仅Deployment、DaemonSet支持配置。</p><h2 id="minreadyseconds-实例可用最短时间" tabindex="-1">minReadySeconds 实例可用最短时间 <a class="header-anchor" href="#minreadyseconds-实例可用最短时间" aria-label="Permalink to &quot;minReadySeconds 实例可用最短时间&quot;">​</a></h2><p>指定新创建的 Pod 在没有任意容器崩溃情况下的最小就绪时间， 只有超出这个时间 Pod 才被视为可用。默认值为 0（Pod 在准备就绪后立即将被视为可用）。</p><h2 id="revisionhistorylimit-最大保留版本数" tabindex="-1">revisionHistoryLimit 最大保留版本数 <a class="header-anchor" href="#revisionhistorylimit-最大保留版本数" aria-label="Permalink to &quot;revisionHistoryLimit 最大保留版本数&quot;">​</a></h2><p>用来设定出于回滚目的所要保留的旧 ReplicaSet 数量。 这些旧 ReplicaSet 会消耗 etcd 中的资源，并占用 kubectl get rs 的输出。 每个 Deployment 修订版本的配置都存储在其 ReplicaSets 中；因此，一旦删除了旧的 ReplicaSet， 将失去回滚到 Deployment 的对应修订版本的能力。 默认情况下，系统保留 10 个旧 ReplicaSet，但其理想值取决于新 Deployment 的频率和稳定性。</p><h2 id="progressdeadlineseconds-升级最大时长" tabindex="-1">progressDeadlineSeconds 升级最大时长 <a class="header-anchor" href="#progressdeadlineseconds-升级最大时长" aria-label="Permalink to &quot;progressDeadlineSeconds 升级最大时长&quot;">​</a></h2><p>指定系统在报告 Deployment 进展失败 之前等待 Deployment 取得进展的秒数。 这类报告会在资源状态中体现为 Type=Progressing、Status=False、 Reason=ProgressDeadlineExceeded。Deployment 控制器将持续重试 Deployment。 将来，一旦实现了自动回滚，Deployment 控制器将在探测到这样的条件时立即回滚 Deployment。</p><p>如果指定，则此字段值需要大于 .spec.minReadySeconds 取值。</p><h2 id="terminationgraceperiodseconds-缩容时间窗" tabindex="-1">terminationGracePeriodSeconds 缩容时间窗 <a class="header-anchor" href="#terminationgraceperiodseconds-缩容时间窗" aria-label="Permalink to &quot;terminationGracePeriodSeconds 缩容时间窗&quot;">​</a></h2><p>优雅删除时间，默认为30秒，删除Pod时发送SIGTERM终止信号，然后等待容器中的应用程序终止执行，如果在terminationGracePeriodSeconds时间内未能终止，则发送SIGKILL的系统信号强行终止。</p>',17);function m(a,h,_,u,S,y){return s(),o("div",null,[e("h1",l,[r(i(a.$frontmatter.title)+" ",1),c]),p])}const b=t(d,[["render",m]]);export{P as __pageData,b as default};
